import React from 'react';
import { Card, CardContent, Box, Typography, Stack } from '@mui/material';
import { LineChart } from '@mui/x-charts';
import response from './response.json';

interface WeeklyForecast {
  day: string;
  high: number;
  low: number;
}

interface WeatherData {
  location: string;
  current: {
    temp: number;
    condition: string;
  };
  weeklyForecast: WeeklyForecast[];
  tempTrend: number[];
}

export default function Widget() {
  const weatherData = response.data as WeatherData;

  return (
    <Card sx={{ width: 'fit-content', minWidth: 320, maxWidth: 450, bgcolor: '#FFFFFF' }} elevation={2}>
      <CardContent sx={{ p: 2.5 }}>
        <Stack spacing={2}>
          <Box>
            <Typography variant="h6" color="text.primary" sx={{ mb: 0.5 }}>
              {weatherData.location}
            </Typography>
            <Typography variant="h3" fontWeight={500} sx={{ color: '#FF5722' }}>
              {weatherData.current.temp}°F
            </Typography>
            <Typography variant="body2" color="text.secondary">
              {weatherData.current.condition}
            </Typography>
          </Box>

          <LineChart
            height={100}
            series={[
              {
                data: weatherData.tempTrend,
                color: '#03A9F4',
                showMark: false,
              },
            ]}
            xAxis={[{ data: [0, 1, 2, 3, 4, 5, 6], hide: true }]}
            margin={{ top: 10, bottom: 10, left: 10, right: 10 }}
            sx={{
              '& .MuiLineElement-root': {
                strokeWidth: 2,
              },
            }}
          />

          <Stack direction="row" spacing={1}>
            {weatherData.weeklyForecast.slice(0, 3).map((forecast) => (
              <Box key={forecast.day}>
                <Typography variant="caption" color="text.secondary">
                  {forecast.day}
                </Typography>
                <Typography variant="body2" fontWeight={500}>
                  {forecast.high}° / {forecast.low}°
                </Typography>
              </Box>
            ))}
          </Stack>
        </Stack>
      </CardContent>
    </Card>
  );
}
